INSERT INTO flashcards (course_id, question_text, answer_text, order_index, difficulty) VALUES
('10000000-0000-0000-0000-000000000021', 'What is a urinary catheter?', 'A flexible tube inserted into the bladder to drain urine. Can be short-term (urethral) or long-term (suprapubic). Indicated for urinary retention, monitoring output, or palliation.', 1, 1),
('10000000-0000-0000-0000-000000000021', 'What is CAUTI?', 'Catheter-Associated Urinary Tract Infection. The most common healthcare-associated infection. Prevention requires strict aseptic technique, regular review, and prompt removal when no longer needed.', 2, 1),
('10000000-0000-0000-0000-000000000021', 'What does a catheter care bundle include?', 'Daily assessment of need, maintain closed drainage system, keep drainage bag below bladder, meatal hygiene with soap and water, documentation, and aseptic technique for bag changes.', 3, 2),
('10000000-0000-0000-0000-000000000021', 'What are the signs of catheter blockage?', 'Reduced or absent urine output despite adequate fluid intake, bladder distension, discomfort, leakage around the catheter (bypassing), and increased confusion or agitation.', 4, 2),
('10000000-0000-0000-0000-000000000021', 'When should you change a catheter?', 'According to manufacturer''s guidelines (typically 12 weeks for long-term catheters), when blocked, when infection is suspected, or when it is clinically indicated. Always document.', 5, 2),
('10000000-0000-0000-0000-000000000021', 'What is a suprapubic catheter?', 'A catheter inserted through the abdominal wall directly into the bladder. Used for long-term catheterisation, after prostatectomy, or when urethral access is not possible.', 6, 3),
('10000000-0000-0000-0000-000000000021', 'What is the correct way to take a catheter specimen of urine (CSU)?', 'Clamp the catheter tubing for 30 minutes, clean the sampling port with an alcohol wipe, use a sterile syringe to aspirate urine from the port. Never disconnect the closed system.', 7, 2),
('10000000-0000-0000-0000-000000000021', 'What size catheter is typically used for long-term catheterisation?', '12-14 French (Charrière) for females, 14-16 French for males. Use the smallest effective size to reduce trauma and blockage risk.', 8, 3);
INSERT INTO flashcards (course_id, question_text, answer_text, order_index, difficulty) VALUES
('10000000-0000-0000-0000-000000000022', 'What are the 4 stages of wound healing?', 'Haemostasis (clotting), Inflammation (immune response), Proliferation (new tissue growth), and Remodelling (scar maturation). Disruption of any stage impairs healing.', 1, 2),
('10000000-0000-0000-0000-000000000022', 'What does TIME stand for in wound bed preparation?', 'Tissue (non-viable removal), Infection/Inflammation, Moisture imbalance, and Edge of wound. A systematic approach to optimising the wound environment for healing.', 2, 2),
('10000000-0000-0000-0000-000000000022', 'What are the signs of wound infection?', 'NERDS (Non-healing, Exudate increase, Red friable tissue, Debris, Smell) for superficial infection. STONEES (Size, Temperature, Os (bone), New wound, Exudate, Erythema/oedema, Smell) for deep infection.', 3, 3),
('10000000-0000-0000-0000-000000000022', 'What is moist wound healing?', 'Maintaining a moist wound environment promotes faster healing, reduces pain, and supports autolytic debridement. Prevents eschar formation and supports cell migration.', 4, 2),
('10000000-0000-0000-0000-000000000022', 'What is debridement?', 'The removal of dead, damaged, or infected tissue to facilitate healing. Methods include sharp/surgical, autolytic (moisture dressings), enzymatic, mechanical, or larval therapy.', 5, 3),
('10000000-0000-0000-0000-000000000022', 'How should you document a wound assessment?', 'Location, dimensions (length, width, depth), tissue type (%, colour), exudate (amount, type, smell), skin surrounding wound, pain, signs of infection, and treatment applied.', 6, 2),
('10000000-0000-0000-0000-000000000022', 'What is a leg ulcer and how do you differentiate types?', 'Venous: shallow, medial gaiter area, irregular edges, liposclerosis. Arterial: deep, punched out, poor peripheral circulation, ABPI <0.8. Mixed aetiology is common. ABPI assessment is essential.', 7, 3),
('10000000-0000-0000-0000-000000000022', 'What is compression therapy and when is it indicated?', 'Application of graduated pressure to the lower limb to improve venous return. Indicated for venous leg ulcers when ABPI is 0.8-1.3. Contraindicated in severe peripheral arterial disease.', 8, 3);
INSERT INTO flashcards (course_id, question_text, answer_text, order_index, difficulty) VALUES
('10000000-0000-0000-0000-000000000024', 'What are the 6 vital signs in NEWS2?', 'Respiration rate, Oxygen saturation (SpO2), Supplemental oxygen, Systolic blood pressure, Pulse rate, Level of consciousness (ACVPU), and Temperature.', 1, 1),
('10000000-0000-0000-0000-000000000024', 'What does ACVPU stand for?', 'Alert, Confusion (new), Voice (responds to), Pain (responds to), Unresponsive. New confusion scores 3 points on NEWS2 — an important change from AVPU.', 2, 2),
('10000000-0000-0000-0000-000000000024', 'What is a NEWS2 score of 5 or more?', 'A medium-to-high clinical risk score requiring urgent review by a clinician. Score 7+ requires emergency review. Always consider clinical context alongside the score.', 3, 2),
('10000000-0000-0000-0000-000000000024', 'What is a normal adult respiratory rate?', '12-20 breaths per minute at rest. Respiratory rate is the most sensitive early indicator of deterioration. Count for a full minute without alerting the patient.', 4, 1),
('10000000-0000-0000-0000-000000000024', 'What is SpO2 Scale 2 in NEWS2?', 'Used for hypercapnic respiratory failure (COPD patients). Target SpO2 is 88-92%. A score of 1-3 is given for values outside this range. Must be prescribed by a clinician.', 5, 3),
('10000000-0000-0000-0000-000000000024', 'What is postural hypotension and why is it important?', 'A drop of ≥20mmHg systolic or ≥10mmHg diastolic on standing. Can cause dizziness and falls. Common in older adults and those on antihypertensives.', 6, 2),
('10000000-0000-0000-0000-000000000024', 'What is SBAR communication?', 'Situation, Background, Assessment, Recommendation — a structured communication tool for escalating concerns about a deteriorating patient. Improves safety and clarity.', 7, 2),
('10000000-0000-0000-0000-000000000024', 'How should NEWS2 observations be trended?', 'Document each set of observations and look for trends over time — a single low score matters less than a progressively rising score. Act on trends, not just single readings.', 8, 2);
INSERT INTO flashcards (course_id, question_text, answer_text, order_index, difficulty) VALUES
('10000000-0000-0000-0000-000000000025', 'What is sepsis?', 'A life-threatening organ dysfunction caused by a dysregulated host response to infection. Without treatment it can lead to septic shock and death. It is a medical emergency.', 1, 1),
('10000000-0000-0000-0000-000000000025', 'What are the red flag signs of sepsis?', 'HR>130, RR>25, SpO2<91%, systolic BP<90, NEWS2≥5, non-blanching rash, mottled/pale/cyanotic skin, not passed urine in 18hrs, altered consciousness. One red flag = call 999.', 2, 2),
('10000000-0000-0000-0000-000000000025', 'What is the "Sepsis Six"?', 'Six time-critical interventions within 1 hour: Give oxygen, Take blood cultures, Give IV antibiotics, Give IV fluid bolus, Check serial lactate, Monitor urine output.', 3, 2),
('10000000-0000-0000-0000-000000000025', 'What is septic shock?', 'Sepsis with circulatory, cellular, and metabolic abnormalities despite adequate fluid resuscitation. Requires vasopressors to maintain MAP ≥65mmHg. Mortality >40%.', 4, 3),
('10000000-0000-0000-0000-000000000025', 'What is the THINK SEPSIS mnemonic?', 'Temperature (high or low), History (of infection or recent procedure), Immune compromise, New confusion, Kicking organ dysfunction (urine, lungs, circulation), Elderly or very young, Pain (new or worsening), Skin changes, ICU admission risk, Sensitive to treatment needed early.', 5, 2),
('10000000-0000-0000-0000-000000000025', 'What is a "soft sign" of deterioration?', 'Subtle changes that may precede obvious deterioration: increased confusion, new incontinence, reduced appetite, increased fatigue, or "just not right" described by the patient or family.', 6, 2),
('10000000-0000-0000-0000-000000000025', 'What is the NEWS2 trigger score requiring immediate clinical review?', 'A score of 7 or above in any individual. Also urgent review at 5-6. However, clinical judgement should always supplement the score.', 7, 2),
('10000000-0000-0000-0000-000000000025', 'What does rapid response mean in a care home setting?', 'Having a clear escalation pathway — knowing when and how to call for help. Following an agreed escalation policy, documenting concerns, and not delaying when concerned about deterioration.', 8, 2);
INSERT INTO flashcards (course_id, question_text, answer_text, order_index, difficulty) VALUES
('10000000-0000-0000-0000-000000000026', 'What is the legal framework for controlled drug management?', 'Misuse of Drugs Act 1971 and Regulations 2001. Schedule 2 CDs require: double-locked storage, a running balance CD register, two-person checking for administration.', 1, 2),
('10000000-0000-0000-0000-000000000026', 'What are the high-risk medications in care homes?', 'Anticoagulants (warfarin, NOACs), insulin, opioids, NSAIDs, digoxin, lithium, methotrexate, and antipsychotics. These have a narrow therapeutic index or high harm potential.', 2, 2),
('10000000-0000-0000-0000-000000000026', 'What is the purpose of medicines reconciliation?', 'Ensuring an accurate medication history when someone moves between care settings. Reduces medication errors by identifying discrepancies between prescribed and actual medication.', 3, 2),
('10000000-0000-0000-0000-000000000026', 'What is the significance of INR in warfarin therapy?', 'INR measures how long blood takes to clot. Target range is typically 2-3 for AF, 2.5-3.5 for mechanical heart valves. INR >4 increases bleeding risk significantly.', 4, 3),
('10000000-0000-0000-0000-000000000026', 'What is the difference between hypoglycaemia and hyperglycaemia?', 'Hypoglycaemia: blood glucose <4mmol/L — emergency, give 15-20g fast-acting carbohydrate. Hyperglycaemia: blood glucose >11mmol/L — may indicate poor control or DKA.', 5, 2),
('10000000-0000-0000-0000-000000000026', 'What are the principles of safe PGD use?', 'Patient Group Directions allow specified medications to be given without a prescription to patients meeting defined criteria. Must be individually signed, reviewed, and time-limited.', 6, 3),
('10000000-0000-0000-0000-000000000026', 'What should a nurse do after making a serious medication error?', 'Immediately assess patient for harm, inform the prescriber and manager, document accurately and contemporaneously, complete an incident form, and engage with the investigation process.', 7, 2),
('10000000-0000-0000-0000-000000000026', 'What is polypharmacy and why does it matter?', 'Taking 5 or more medications simultaneously. Common in older adults. Increases risk of adverse drug reactions, falls, and hospital admissions. Regular medication reviews essential.', 8, 2);
INSERT INTO flashcards (course_id, question_text, answer_text, order_index, difficulty) VALUES
('10000000-0000-0000-0000-000000000027', 'When is supplemental oxygen indicated?', 'SpO2 below target: 94-98% for most patients, 88-92% for hypercapnic patients (COPD/type 2 respiratory failure). Must be prescribed by a clinician.', 1, 1),
('10000000-0000-0000-0000-000000000027', 'What is hypercapnic respiratory failure?', 'Type 2 respiratory failure with elevated CO2 (PaCO2 >6kPa) due to hypoventilation. Common in COPD. High-flow oxygen can suppress drive to breathe. Target SpO2 88-92%.', 2, 3),
('10000000-0000-0000-0000-000000000027', 'What are the different oxygen delivery devices?', 'Nasal cannulae (24-44%, low flow), Simple face mask (35-60%), Venturi mask (24-60% controlled), Non-rebreather mask (60-90%, high flow emergencies), Humidified high flow nasal oxygen (HFNO).', 3, 2),
('10000000-0000-0000-0000-000000000027', 'What are risks of excessive oxygen therapy?', 'Hypercapnic respiratory failure in COPD (respiratory depression), oxygen toxicity with prolonged high-flow use, absorptive atelectasis, and free radical lung injury.', 4, 3),
('10000000-0000-0000-0000-000000000027', 'How should you monitor a patient receiving oxygen therapy?', 'Continuous SpO2 monitoring when initiating therapy, regular clinical assessment, ABG interpretation for high-risk patients, and documentation of delivery device, flow rate, and SpO2 response.', 5, 2),
('10000000-0000-0000-0000-000000000027', 'What fire risks does oxygen therapy present?', 'Oxygen accelerates combustion. Strict no smoking rules, no naked flames, and keep cylinders away from heat sources. Oxygen cylinders must be stored securely and checked regularly.', 6, 2),
('10000000-0000-0000-0000-000000000027', 'What is a Venturi mask and why is it used?', 'A mask that delivers a precise percentage of oxygen using colour-coded Venturi valves. Used when controlled oxygen delivery is essential, e.g., COPD. Provides reliable FiO2.', 7, 2),
('10000000-0000-0000-0000-000000000027', 'When should oxygen be prescribed in advance for emergencies?', 'For patients with known COPD or hypercapnic respiratory failure who may need emergency oxygen. Pre-prescribed emergency oxygen with specific targets prevents harm from over-oxygenation.', 8, 3);
INSERT INTO flashcards (course_id, question_text, answer_text, order_index, difficulty) VALUES
('10000000-0000-0000-0000-000000000028', 'What is the difference between Type 1 and Type 2 diabetes?', 'Type 1: autoimmune, no insulin production, requires insulin therapy. Type 2: insulin resistance and relative insulin deficiency, managed with lifestyle, oral medications, and sometimes insulin.', 1, 1),
('10000000-0000-0000-0000-000000000028', 'What is HbA1c and what does it measure?', 'Glycated haemoglobin — reflects average blood glucose over the past 2-3 months. NICE target: <48mmol/mol (6.5%) for T2DM. Higher targets may be appropriate for frail older adults.', 2, 2),
('10000000-0000-0000-0000-000000000028', 'What are the signs of hypoglycaemia?', 'Trembling, sweating, palpitations, hunger, anxiety, pallor (<4mmol/L). Severe: confusion, fits, unconsciousness. Treat with 15-20g fast-acting carbohydrate and recheck after 15 minutes.', 3, 2),
('10000000-0000-0000-0000-000000000028', 'What is DKA (Diabetic Ketoacidosis)?', 'A life-threatening emergency in Type 1 diabetes: hyperglycaemia, ketonaemia, metabolic acidosis. Symptoms: vomiting, abdominal pain, fruity breath, confusion. Medical emergency — call 999.', 4, 3),
('10000000-0000-0000-0000-000000000028', 'How should insulin be stored?', 'Unopened: refrigerator (2-8°C). In use: room temperature (below 25°C) for up to 28 days (check manufacturer''s guidelines). Never freeze insulin.', 5, 2),
('10000000-0000-0000-0000-000000000028', 'What are sick day rules for insulin-dependent patients?', 'Never stop insulin when unwell. Monitor blood glucose every 1-2 hours. Monitor ketones if glucose >14. Stay hydrated. Adjust insulin dose according to guidance. Seek medical help if vomiting or ketones >3+.', 6, 3),
('10000000-0000-0000-0000-000000000028', 'What is the foot care requirement for diabetic residents?', 'Annual foot check, regular inspection for sores/breaks, appropriate footwear, prompt referral for any foot problems. Neuropathy and ischaemia make diabetic feet high-risk for ulceration.', 7, 2),
('10000000-0000-0000-0000-000000000028', 'What is HHNS (Hyperosmolar Hyperglycaemic State)?', 'A serious condition in Type 2 diabetes: extreme hyperglycaemia (>30mmol/L), severe dehydration, no significant ketosis. More common in older adults. Treated with careful IV fluids.', 8, 3);
INSERT INTO flashcards (course_id, question_text, answer_text, order_index, difficulty) VALUES
('10000000-0000-0000-0000-000000000029', 'What are the 4 themes of the NMC Code (2018)?', 'Prioritise people, Practise effectively, Preserve safety, Promote professionalism and trust. The Code is the foundation of nursing and midwifery practice.', 1, 1),
('10000000-0000-0000-0000-000000000029', 'What are the revalidation requirements for a nurse?', 'Every 3 years: 450 practice hours, 35 hours CPD (20 participatory), 5 written reflective accounts, reflective discussion with NMC registrant, professional indemnity, health and character declaration, and confirmation.', 2, 2),
('10000000-0000-0000-0000-000000000029', 'What is a "reflective account" in NMC revalidation?', 'A written account reflecting on an experience and relating it to the Code. Must describe what you learnt and how it changed your practice. 5 required over the 3-year period.', 3, 2),
('10000000-0000-0000-0000-000000000029', 'What is "participatory CPD" in revalidation?', 'CPD undertaken with other professionals, such as attending conferences, training courses, workshops, or meetings. At least 20 of the 35 required hours must be participatory.', 4, 2),
('10000000-0000-0000-0000-000000000029', 'What happens if a nurse fails to revalidate?', 'Their registration is removed. They cannot legally practise as a nurse in the UK. They must apply for restoration, which requires meeting current requirements.', 5, 2),
('10000000-0000-0000-0000-000000000029', 'What is the role of a "confirmer" in NMC revalidation?', 'A registered NMC professional who confirms the nurse has met revalidation requirements. Should be someone who knows your practice. Ideally the nurse''s line manager.', 6, 2),
('10000000-0000-0000-0000-000000000029', 'What is the NMC''s Fitness to Practise process?', 'An investigation into concerns about a nurse''s fitness to practise. Can result in: warning, conditions of practice, suspension, or removal from the register. Designed to protect the public.', 7, 3),
('10000000-0000-0000-0000-000000000029', 'What must a nurse do if they make an error?', 'Act with candour — tell the person affected and apologise. Report to manager and complete an incident form. Reflect on what happened. Seek support. This is a professional and legal obligation.', 8, 2);
INSERT INTO flashcards (course_id, question_text, answer_text, order_index, difficulty) VALUES
('10000000-0000-0000-0000-000000000030', 'What is clinical governance?', 'A framework through which NHS and care organisations are accountable for continuously improving quality of their services and safeguarding high standards of care.', 1, 1),
('10000000-0000-0000-0000-000000000030', 'What are the 7 pillars of clinical governance?', 'Clinical audit, Research and effectiveness, Education and training, Patient and public involvement, Risk management, Staffing and staff management, and Information management.', 2, 2),
('10000000-0000-0000-0000-000000000030', 'What is the purpose of a clinical audit?', 'To measure current practice against evidence-based standards, identify gaps, implement improvements, and re-audit to complete the cycle. The audit cycle: plan, collect data, analyse, act, re-audit.', 3, 2),
('10000000-0000-0000-0000-000000000030', 'What is a "Serious Incident" (SI)?', 'An adverse event where the consequences to patients, staff, or organisations are so significant that a detailed review and response are required beyond normal management processes.', 4, 2),
('10000000-0000-0000-0000-000000000030', 'What is root cause analysis (RCA)?', 'A method of investigation that seeks to identify the fundamental causes of an incident rather than just the immediate cause. Leads to systemic changes to prevent recurrence.', 5, 3),
('10000000-0000-0000-0000-000000000030', 'What does CQC inspect in care homes?', 'Five key questions: Safe, Effective, Caring, Responsive, Well-led. Each area inspected against fundamental standards. Ratings: Outstanding, Good, Requires Improvement, Inadequate.', 6, 2),
('10000000-0000-0000-0000-000000000030', 'What is CQUIN?', 'Commissioning for Quality and Innovation — a framework that rewards providers for delivering quality improvements. Links a proportion of provider income to quality performance.', 7, 3),
('10000000-0000-0000-0000-000000000030', 'What is a "learning culture" in clinical governance?', 'An environment where errors are reported without fear, investigations are conducted fairly, learning is shared across teams, and improvements are implemented. Opposite of a blame culture.', 8, 2);
